export class GrowthBook {
  constructor(options = {}) {
    this.options = options;
    this.attributes = options.attributes || {};
    this.payload = { features: {} };
    this.features = {};
  }

  async init() {
    return { success: false, source: 'deepcode-shim' };
  }

  async refreshFeatures() {
    return { success: false, source: 'deepcode-shim' };
  }

  getPayload() {
    return this.payload;
  }

  async setPayload(payload) {
    this.payload = payload || { features: {} };
    this.features = this.payload.features || {};
  }

  getFeatures() {
    return this.features;
  }

  getFeatureValue(_feature, fallback) {
    return fallback;
  }

  isOn() {
    return false;
  }

  setAttributes(attributes = {}) {
    this.attributes = attributes;
  }

  setForcedFeatures(features = {}) {
    this.features = features;
  }

  destroy() {}
}
